import asyncio
import json

class Player:
    def __init__(self, id):
        self.id = id
        self.inventory = []

class InventorySystem:
    def __init__(self):
        self.players = {}
        self.lock = asyncio.Lock()

    async def add_player(self, player_id):
        if player_id not in self.players:
            self.players[player_id] = Player(player_id)

    async def remove_player(self, player_id):
        if player_id in self.players:
            del self.players[player_id]

    async def transfer_item(self, sender_id, receiver_id, item_id):
        async with self.lock:
            if sender_id not in self.players or receiver_id not in self.players:
                return False

            sender = self.players[sender_id]
            receiver = self.players[receiver_id]

            if item_id in [item['id'] for item in sender.inventory]:
                item_index = sender.inventory.index(next(item for item in sender.inventory if item['id'] == item_id))
                sender.inventory.pop(item_index)
                receiver.inventory.append({'id': item_id})
                return True
        return False

    async def update_item_ownership(self, player_id, item_id):
        async with self.lock:
            if player_id not in self.players or item_id not in [item['id'] for item in self.players[player_id].inventory]:
                return False

            item_index = self.players[player_id].inventory.index(next(item for item in self.players[player_id].inventory if item['id'] == item_id))
            self.players[player_id].inventory.pop(item_index)
            await self.add_player(player_id)
        return True

async def handle_client(ws, player_id):
    async for message in ws:
        data = json.loads(message)
        if data['type'] == 'add_item':
            self.players[player_id].inventory.append({'id': data['item_id']})
        elif data['type'] == 'remove_item':
            item_index = next((i for i, item in enumerate(self.players[player_id].inventory) if item['id'] == data['item_id']), None)
            if item_index is not None:
                self.players[player_id].inventory.pop(item_index)
        elif data['type'] == 'trade':
            await asyncio.gather(
                inventory_system.transfer_item(player_id, data['receiver_id'], data['item_id']),
                inventory_system.transfer_item(data['receiver_id'], player_id, data['item_id'])
            )

async def main():
    global inventory_system
    inventory_system = InventorySystem()

    async with websockets.serve(handle_client, 'localhost', 8765):
        await asyncio.Future()  # run forever

if __name__ == "__main__":
    asyncio.run(main())